css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #0d0d0d; color: white; }
.navbar { display: flex; align-items: center; justify-content: space-between; padding: 22px 60px; }
.brand { font-size: 20px; font-weight: 800; }
.nav-links { display: flex; gap: 30px; }
.nav-links a { color: rgba(255,255,255,0.5); text-decoration: none; font-size: 13.5px; font-weight: 600; }
.nav-links a.active { color: #facc15; }
.hero { position: relative; height: 380px; margin: 0 24px; border-radius: 24px; overflow: hidden; }
.hero-img { position: absolute; inset: 0; background: linear-gradient(135deg, #3a2a10, #0d0d0d); display: flex; align-items: center; justify-content: center; font-size: 160px; }
.hero-overlay { position: absolute; bottom: 0; left: 0; padding: 32px; background: linear-gradient(180deg, transparent, rgba(0,0,0,0.7)); width: 100%; }
.hero-overlay .cat { display: inline-block; background: rgba(250,204,21,0.15); color: #facc15; font-size: 12px; font-weight: 700; padding: 4px 12px; border-radius: 999px; margin-bottom: 10px; }
.hero-overlay h1 { font-size: 36px; font-weight: 800; }
.hero-overlay p { color: rgba(255,255,255,0.55); font-size: 13.5px; margin-top: 6px; }
.grid { display: grid; grid-template-columns: repeat(4, 1fr); grid-auto-rows: 180px; gap: 12px; padding: 24px; }
.grid-item { position: relative; border-radius: 16px; overflow: hidden; cursor: pointer; }
.grid-item.tall { grid-row: span 2; }
.grid-item.wide { grid-column: span 2; }
.ph { position: absolute; inset: 0; background: #1a1a1a; display: flex; align-items: center; justify-content: center; font-size: 50px; transition: 0.3s; }
.grid-item:hover .ph { transform: scale(1.08); }
.ph-info { position: absolute; bottom: 0; left: 0; padding: 14px 16px; background: linear-gradient(180deg, transparent, rgba(0,0,0,0.75)); width: 100%; }
.ph-info .cat { display: block; font-size: 10.5px; color: #facc15; font-weight: 700; text-transform: uppercase; letter-spacing: 0.05em; margin-bottom: 2px; }
.ph-info h3 { font-size: 14px; font-weight: 700; }
.modal { position: fixed; inset: 0; background: rgba(0,0,0,0.85); display: none; align-items: center; justify-content: center; z-index: 10; }
.modal.show { display: flex; }
.modal-content { text-align: center; }
.modal-ph { width: 320px; height: 320px; background: #1a1a1a; border-radius: 16px; display: flex; align-items: center; justify-content: center; font-size: 120px; margin-bottom: 18px; }
.modal-content h3 { font-size: 20px; font-weight: 700; }
@media (max-width: 900px) { .navbar { padding: 22px 24px; } .nav-links { display: none; } .hero { height: 240px; } .hero-overlay h1 { font-size: 24px; } .grid { grid-template-columns: repeat(2, 1fr); grid-auto-rows: 140px; } .grid-item.wide { grid-column: span 2; } }

js:
function openPhoto(el) {
  const title = el.querySelector('h3').textContent;
  const emoji = el.querySelector('.ph').textContent;
  document.getElementById('modalTitle').textContent = title;
  document.getElementById('modalPh').textContent = emoji;
  document.getElementById('modal').classList.add('show');
}

function closeModal() {
  document.getElementById('modal').classList.remove('show');
}
